Patch Set 1:

The definition of security_inode_notifysecctx is:

   int security_inode_notifysecctx(struct inode *inode, void *ctx, u32 ctxlen)
   {
           return security_ops->inode_notifysecctx(inode, ctx, ctxlen);
   }


And we have:

   .inode_notifysecctx =           selinux_inode_notifysecctx


The source for selinux_inode_notifysecctx() says:

   /*
    *      called with inode->i_mutex locked
    */
   static int selinux_inode_notifysecctx(struct inode *inode, void *ctx, u32 ctxlen)
   {
           return selinux_inode_setsecurity(inode, XATTR_SELINUX_SUFFIX, ctx, ctxlen, 0);
   }


So why would you consider this kernel comment is wrong?

-1 until this is clarified.

Patch Set 1:

I have not found any action which need to be protected by inode_lock at selinux_inode_setsecurity(). 
static int selinux_inode_setsecurity(struct inode *inode, const char *name,
				     const void *value, size_t size, int flags)
{
	struct inode_security_struct *isec = inode_security_novalidate(inode);
	u32 newsid;
	int rc;

	if (strcmp(name, XATTR_SELINUX_SUFFIX))
		return -EOPNOTSUPP;

	if (!value || !size)
		return -EACCES;

	rc = security_context_to_sid(value, size, &newsid, GFP_KERNEL);
	if (rc)
		return rc;

	spin_lock(&isec->lock);
	isec->sclass = inode_mode_to_security_class(inode->i_mode);
	isec->sid = newsid;
	isec->initialized = LABEL_INITIALIZED;
	spin_unlock(&isec->lock);
	return 0;
}
Probably, some security implementation requires inode_lock, but SELinux doesn't. And Lustre doesn't use other security imp. I have not found any inode_lock for security_inode_notifysecctx at kernel also, nfs doesn't hold it, and kernfs too.
